	test(16, CMPLX(strtod("inf", NULL), nan("")), CMPLX(nan(""), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), CMPLX(nan(""), strtod("inf", NULL)), 0 | MF_ANYSIGN2);
