	test(20, CMPLX(-0.1234, strtod("inf", NULL)), CMPLX(0x1.921fb54442d17p+0, strtod("-inf", NULL)), CMPLX(0x1.921fb54442d18p+0, strtod("-inf", NULL)), CMPLX(0x1.921fb54442d19p+0, strtod("-inf", NULL)), 0);
	test(21, CMPLX(nan(""), strtod("inf", NULL)), CMPLX(nan(""), strtod("-inf", NULL)), CMPLX(nan(""), strtod("-inf", NULL)), CMPLX(nan(""), strtod("-inf", NULL)), 0);
	test(22, CMPLX(strtod("inf", NULL), strtod("inf", NULL)), CMPLX(0x1.921fb54442d17p-1, strtod("-inf", NULL)), CMPLX(0x1.921fb54442d18p-1, strtod("-inf", NULL)), CMPLX(0x1.921fb54442d19p-1, strtod("-inf", NULL)), 0);
	test(23, CMPLX(strtod("-inf", NULL), strtod("inf", NULL)), CMPLX(0x1.2d97c7f3321d1p+1, strtod("-inf", NULL)), CMPLX(0x1.2d97c7f3321d2p+1, strtod("-inf", NULL)), CMPLX(0x1.2d97c7f3321d3p+1, strtod("-inf", NULL)), 0);
	test(24, CMPLX(0.0, strtod("inf", NULL)), CMPLX(0x1.921fb54442d17p+0, strtod("-inf", NULL)), CMPLX(0x1.921fb54442d18p+0, strtod("-inf", NULL)), CMPLX(0x1.921fb54442d19p+0, strtod("-inf", NULL)), 0);
	test(25, CMPLX(0.9001, strtod("-inf", NULL)), CMPLX(0x1.921fb54442d17p+0, strtod("inf", NULL)), CMPLX(0x1.921fb54442d18p+0, strtod("inf", NULL)), CMPLX(0x1.921fb54442d19p+0, strtod("inf", NULL)), 0);
